// Evaluar si la anomalía requiere corte automático de emergencia
const item = $('Switch Severidad').item.json;
const sev = (item.severidad || '').toString().toLowerCase();
const desviacion = Number(item.desviacion) || 0;
const area = item.area || '';
const modo = (item.modo || 'normal').toLowerCase();

// No auto-cortar si es una simulación de anomalía (modo explícito del simulador)
const esSimulacion = modo !== 'normal' && modo !== 'ok' && modo !== 'relay_off';

// Reglas de auto-corte:
// 1. Severidad Crítica con desviación > 150% (umbral alto)
// 2. NO es simulación de anomalía
// 3. Área sensible (sala_servidores queda excluida por seguridad)
const areasProtegidas = ['sala_servidores'];
const requiereCorte = !esSimulacion && sev.includes('crit') && desviacion > 150 && !areasProtegidas.includes(area);

return [{ json: { ...item, requiere_corte: requiereCorte, motivo: requiereCorte ? `Auto-corte: ${desviacion}% desviación` : 'Solo alerta' } }];
